/* ── COVER ── */
.cover-logo { position: relative; z-index: 1; }
.cover-title {
    position: relative;
    z-index: 1;
    margin-top: 64px;
}
.cover-title h1 {
    font-size: 24px;
    font-weight: 800;
    color: var(--blue);
    line-height: 1.15;
    margin-bottom: 20px;
}
.cover-date {
    font-size: 13px;
    font-weight: 600;
    color: var(--text);
}
.cover-bottom {
    position: absolute;
    bottom: 56px;
    left: 56px;
    z-index: 1;
}
.cover-bottom p {
    font-size: 13.5px;
    color: var(--text);
    line-height: 1.7;
    margin-bottom: 2px;
}

/* ── HEADINGS ── */
h2 {
    font-size: 19px;
    font-weight: 700;
    color: var(--blue);
    margin-bottom: 18px;
}
h2.spaced { margin-top: 34px; }
h3 {
    font-size: 13.5px;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 6px;
    margin-top: 20px;
}
h3.first { margin-top: 0; }
h3.section { margin-top: 26px; margin-bottom: 4px; }

/* ── BODY TEXT ── */
p {
    font-size: 13.5px;
    line-height: 1.75;
    color: var(--text-muted);
    margin-bottom: 12px;
}
p.highlight {
    color: var(--blue);
    font-weight: 700;
    margin-bottom: 14px;
}

/* ── LISTS ── */
ul { list-style: disc; padding-left: 22px; margin-bottom: 16px; }
ul li {
    font-size: 13.5px;
    line-height: 1.75;
    color: var(--text-muted);
    margin-bottom: 3px;
}

/* Numbered list (funcionalidades / próximos passos) */
.num-list { list-style: none; padding: 0; margin-bottom: 16px; }
.num-list li {
    display: flex;
    gap: 10px;
    font-size: 13.5px;
    line-height: 1.75;
    color: var(--text-muted);
    margin-bottom: 18px;
    align-items: flex-start;
}
.num-list li .n {
    color: var(--blue);
    font-weight: 700;
    min-width: 22px;
    flex-shrink: 0;
    padding-top: 1px;
}

/* ── PHASES ── */
.phase {
    font-size: 13.5px;
    line-height: 1.75;
    color: var(--text-muted);
    margin-bottom: 14px;
}
.phase .lbl { color: var(--blue); font-weight: 700; }

/* ── INVESTMENT ── */
.invest-total { font-size: 14px; font-weight: 700; color: var(--text); margin-bottom: 22px; }
.payment-heading { font-size: 14px; font-weight: 700; color: var(--blue); margin-bottom: 12px; }
.payment-row { font-size: 13.5px; line-height: 1.75; color: var(--text-muted); margin-bottom: 4px; }
.payment-row strong { color: var(--text); font-weight: 700; }

/* ── CLOSING ── */
.closing-section { margin-top: 52px; }
.closing-quote { font-size: 15px; font-weight: 700; color: var(--blue); line-height: 1.6; margin-bottom: 2px; }
.company-info { margin-top: 24px; font-size: 12.5px; color: var(--text-muted); line-height: 1.75; }
.validity { margin-top: 14px; font-size: 12.5px; color: var(--text-muted); }

/* ── FOOTER ── */
.footer {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    padding: 0 56px 32px;
    z-index: 2;
}
.footer-line { height: 2px; background: #e5e7eb80; margin-bottom: 24px; }
.footer-row { display: flex; justify-content: space-between; align-items: center; }
.pg-num { font-size: 12.5px; color: var(--blue); font-weight: 700; }

