input.command:
powershell -Command "
\$file = 'c:/Users/charl/OneDrive/Área de Trabalho/WA/Modelo de proposta/proposta-template.html'
\$content = [IO.File]::ReadAllText(\$file)

# Remove footers duplicados - manter apenas os 2 últimos
\$footerPattern = '<div class=\"footer\">[\\s\\S]*?</div>[\\r\\n\\s]*</div>'
\$footers = [regex]::Matches(\$content, \$footerPattern)

Write-Host \"Found \$(\$footers.Count) footers\"

if (\$footers.Count -gt 2) {
    # Remove all but last 2 footers
    for (\$i = 0; \$i -lt \$footers.Count - 2; \$i++) {
        \$content = \$content.Replace(\$footers[\$i].Value, '')
    }
}

# Remove background images duplicadas - manter apenas os 2 últimos
\$bgPattern = '<img class=\"page-bg\"[^>]*>'
\$backgrounds = [regex]::Matches(\$content, \$bgPattern)

Write-Host \"Found \$(\$backgrounds.Count) backgrounds\"

if (\$backgrounds.Count -gt 2) {
    # Remove all but last 2 backgrounds
    for (\$i = 0; \$i -lt \$backgrounds.Count - 2; \$i++) {
        \$content = \$content.Replace(\$backgrounds[\$i].Value, '')
    }
}

[IO.File]::WriteAllText(\$file, \$content)
Write-Host 'Cleaned up proposta-template.html'
"
